    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ----------------------------------------------------------------
    // follow()
    // ----------------------------------------------------------------

    @Test
    fun `should follow successfully when valid follower and followee`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val savedEntity = FollowEntity(
            id = "follow-id-1",
            followerId = followerId,
            followeeId = followeeId,
            createdAt = LocalDateTime.now(),
        )
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>()))
            .thenReturn(savedEntity)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.followId).isEqualTo("follow-id-1")
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
        verify(followRepository).save(any<FollowEntity>())
    }

    @Test
    fun `should throw SelfFollowException when follower and followee are the same user`() {
        // given
        val userId = "user-A"

        // when & then
        val exception = assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
        assertThat(exception.message).contains("자기 자신을 팔로우할 수 없습니다")
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following the user`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when & then
        val exception = assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
        assertThat(exception.message).contains("이미 팔로우한 사용자입니다")
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should persist FollowEntity with correct follower and followee ids`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val savedEntity = FollowEntity(
            id = "follow-id-new",
            followerId = followerId,
            followeeId = followeeId,
        )
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>()))
            .thenReturn(savedEntity)

        // when
        userService.follow(followerId, followeeId)

        // then
        verify(followRepository).save(
            org.mockito.kotlin.argThat { entity ->
                entity.followerId == followerId && entity.followeeId == followeeId
            }
        )
    }

    // ----------------------------------------------------------------
    // unfollow()
    // ----------------------------------------------------------------

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should throw FollowNotFoundException when trying to unfollow a non-existing relationship`() {
