    // getFollowings()
    // ----------------------------------------------------------------

    @Test
    fun `should return list of followings for the given user`() {
        // given
        val userId = "user-A"
        val entities = listOf(
            FollowEntity(id = "follow-1", followerId = userId, followeeId = "user-B"),
            FollowEntity(id = "follow-2", followerId = userId, followeeId = "user-C"),
        )
        whenever(followRepository.findByFollowerId(userId)).thenReturn(entities)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result[0].followeeId).isEqualTo("user-B")
        assertThat(result[1].followeeId).isEqualTo("user-C")
        assertThat(result).allMatch { it.followerId == userId }
