        // given
        val userId = "user-new"
        whenever(followRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ----------------------------------------------------------------
    // getFollowers()
    // ----------------------------------------------------------------

    @Test
    fun `should return list of followers for the given user`() {
        // given
        val userId = "user-B"
        val entities = listOf(
            FollowEntity(id = "follow-10", followerId = "user-A", followeeId = userId),
            FollowEntity(id = "follow-11", followerId = "user-C", followeeId = userId),
