        whenever(followRepository.findByFolloweeId(userId)).thenReturn(entities)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result[0].followerId).isEqualTo("user-A")
        assertThat(result[1].followerId).isEqualTo("user-C")
        assertThat(result).allMatch { it.followeeId == userId }
        verify(followRepository).findByFolloweeId(userId)
