package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.repository.follow.FollowRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

class AlreadyFollowingException(message: String) : RuntimeException(message)
class SelfFollowException(message: String) : RuntimeException(message)
class FollowNotFoundException(message: String) : RuntimeException(message)

data class FollowResult(
    val followId: String,
    val followerId: String,
    val followeeId: String,
)

@Service
class UserService(
    private val followRepository: FollowRepository,
) {
    @Transactional
    fun follow(followerId: String, followeeId: String): FollowResult {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }
        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException("이미 팔로우한 사용자입니다.")
        }
        val entity = followRepository.save(
            FollowEntity(followerId = followerId, followeeId = followeeId)
        )
        return FollowResult(
            followId = entity.id,
            followerId = entity.followerId,
            followeeId = entity.followeeId,
        )
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw FollowNotFoundException("팔로우 관계가 존재하지 않습니다.")
        }
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean =
        followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)

    @Transactional(readOnly = true)
    fun getFollowingCount(userId: String): Long =
        followRepository.countByFollowerId(userId)

    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Long =
        followRepository.countByFolloweeId(userId)

    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<FollowResult> =
        followRepository.findByFollowerId(userId).map {
            FollowResult(followId = it.id, followerId = it.followerId, followeeId = it.followeeId)
        }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<FollowResult> =
        followRepository.findByFolloweeId(userId).map {
            FollowResult(followId = it.id, followerId = it.followerId, followeeId = it.followeeId)
        }
}
