package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.repository.follow.FollowRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.time.LocalDateTime

@ExtendWith(MockitoExtension::class)
class UserServiceFollowTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ----------------------------------------------------------------
    // follow()
    // ----------------------------------------------------------------

    @Test
    fun `should follow successfully when valid follower and followee`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val savedEntity = FollowEntity(
            id = "follow-id-1",
            followerId = followerId,
            followeeId = followeeId,
            createdAt = LocalDateTime.now(),
        )
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>()))
            .thenReturn(savedEntity)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.followId).isEqualTo("follow-id-1")
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
        verify(followRepository).save(any<FollowEntity>())
    }

    @Test
    fun `should throw SelfFollowException when follower and followee are the same user`() {
        // given
        val userId = "user-A"

        // when & then
        val exception = assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
        assertThat(exception.message).contains("자기 자신을 팔로우할 수 없습니다")
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following the user`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when & then
        val exception = assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
        assertThat(exception.message).contains("이미 팔로우한 사용자입니다")
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should persist FollowEntity with correct follower and followee ids`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val savedEntity = FollowEntity(
            id = "follow-id-new",
            followerId = followerId,
            followeeId = followeeId,
        )
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>()))
            .thenReturn(savedEntity)

        // when
        userService.follow(followerId, followeeId)

        // then
        verify(followRepository).save(
            org.mockito.kotlin.argThat { entity ->
                entity.followerId == followerId && entity.followeeId == followeeId
            }
        )
    }

    // ----------------------------------------------------------------
    // unfollow()
    // ----------------------------------------------------------------

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should throw FollowNotFoundException when trying to unfollow a non-existing relationship`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when & then
        val exception = assertThrows<FollowNotFoundException> {
            userService.unfollow(followerId, followeeId)
        }
        assertThat(exception.message).contains("팔로우 관계가 존재하지 않습니다")
        verify(followRepository, never()).deleteByFollowerIdAndFolloweeId(any(), any())
    }

    // ----------------------------------------------------------------
    // isFollowing()
    // ----------------------------------------------------------------

    @Test
    fun `should return true when user is following the target`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should return false when user is not following the target`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isFalse()
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    // ----------------------------------------------------------------
    // getFollowingCount()
    // ----------------------------------------------------------------

    @Test
    fun `should return following count for the given user`() {
        // given
        val userId = "user-A"
        whenever(followRepository.countByFollowerId(userId)).thenReturn(5L)

        // when
        val count = userService.getFollowingCount(userId)

        // then
        assertThat(count).isEqualTo(5L)
        verify(followRepository).countByFollowerId(userId)
    }

    @Test
    fun `should return zero following count when user has no followings`() {
        // given
        val userId = "user-new"
        whenever(followRepository.countByFollowerId(userId)).thenReturn(0L)

        // when
        val count = userService.getFollowingCount(userId)

        // then
        assertThat(count).isEqualTo(0L)
    }

    // ----------------------------------------------------------------
    // getFollowerCount()
    // ----------------------------------------------------------------

    @Test
    fun `should return follower count for the given user`() {
        // given
        val userId = "user-B"
        whenever(followRepository.countByFolloweeId(userId)).thenReturn(100L)

        // when
        val count = userService.getFollowerCount(userId)

        // then
        assertThat(count).isEqualTo(100L)
        verify(followRepository).countByFolloweeId(userId)
    }

    @Test
    fun `should return zero follower count when user has no followers`() {
        // given
        val userId = "user-new"
        whenever(followRepository.countByFolloweeId(userId)).thenReturn(0L)

        // when
        val count = userService.getFollowerCount(userId)

        // then
        assertThat(count).isEqualTo(0L)
    }

    // ----------------------------------------------------------------
    // getFollowings()
    // ----------------------------------------------------------------

    @Test
    fun `should return list of followings for the given user`() {
        // given
        val userId = "user-A"
        val entities = listOf(
            FollowEntity(id = "follow-1", followerId = userId, followeeId = "user-B"),
            FollowEntity(id = "follow-2", followerId = userId, followeeId = "user-C"),
        )
        whenever(followRepository.findByFollowerId(userId)).thenReturn(entities)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result[0].followeeId).isEqualTo("user-B")
        assertThat(result[1].followeeId).isEqualTo("user-C")
        assertThat(result).allMatch { it.followerId == userId }
        verify(followRepository).findByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user has no followings`() {
        // given
        val userId = "user-new"
        whenever(followRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ----------------------------------------------------------------
    // getFollowers()
    // ----------------------------------------------------------------

    @Test
    fun `should return list of followers for the given user`() {
        // given
        val userId = "user-B"
        val entities = listOf(
            FollowEntity(id = "follow-10", followerId = "user-A", followeeId = userId),
            FollowEntity(id = "follow-11", followerId = "user-C", followeeId = userId),
        )
        whenever(followRepository.findByFolloweeId(userId)).thenReturn(entities)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result[0].followerId).isEqualTo("user-A")
        assertThat(result[1].followerId).isEqualTo("user-C")
        assertThat(result).allMatch { it.followeeId == userId }
        verify(followRepository).findByFolloweeId(userId)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "user-new"
        whenever(followRepository.findByFolloweeId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
    }
}

